/*
 * Disclaimer: All test cases are generated by codex against the codebase
 */

#include "gpjson/cuda/cuda.hpp"
#include "gpjson/cuda/error.hpp"

#include <gtest/gtest.h>

#include <utility>
#include <vector>

namespace {

void skip_if_cuda_unavailable() {
  if (!gpjson::cuda::device_available()) {
    GTEST_SKIP() << "CUDA device unavailable";
  }
}

} // namespace

TEST(DeviceArrayTest, DefaultAndZeroByteArraysAreEmpty) {
  gpjson::cuda::DeviceArray empty;
  EXPECT_TRUE(empty.empty());
  EXPECT_EQ(empty.data(), nullptr);
  EXPECT_EQ(empty.size_bytes(), 0);

  gpjson::cuda::DeviceArray zero(0);
  EXPECT_TRUE(zero.empty());
  EXPECT_EQ(zero.data(), nullptr);
  EXPECT_EQ(zero.size_bytes(), 0);

  zero.copy_from_host(nullptr, 0);
  zero.copy_to_host(nullptr, 0);
  zero.memset(0);
}

TEST(DeviceArrayTest, AllocationReportsRequestedByteSize) {
  skip_if_cuda_unavailable();

  gpjson::cuda::DeviceArray array(16);
  EXPECT_FALSE(array.empty());
  EXPECT_NE(array.data(), nullptr);
  EXPECT_EQ(array.size_bytes(), 16);
}

TEST(DeviceArrayTest, CopyRoundTripPreservesData) {
  skip_if_cuda_unavailable();

  std::vector<int> input{1, 2, 3, 4};
  std::vector<int> output(input.size(), 0);
  gpjson::cuda::DeviceArray array(input.size() * sizeof(int));

  array.copy_from_host(input.data(), input.size() * sizeof(int));
  array.copy_to_host(output.data(), output.size() * sizeof(int));

  EXPECT_EQ(output, input);
}

TEST(DeviceArrayTest, MemsetClearsDeviceArray) {
  skip_if_cuda_unavailable();

  std::vector<int> input{1, 2, 3, 4};
  std::vector<int> output(input.size(), -1);
  gpjson::cuda::DeviceArray array(input.size() * sizeof(int));

  array.copy_from_host(input.data(), input.size() * sizeof(int));
  array.memset(0);
  array.copy_to_host(output.data(), output.size() * sizeof(int));

  EXPECT_EQ(output, std::vector<int>(input.size(), 0));
}

TEST(DeviceArrayTest, MoveConstructorTransfersOwnership) {
  skip_if_cuda_unavailable();

  gpjson::cuda::DeviceArray source(16);
  void *source_ptr = source.data();

  gpjson::cuda::DeviceArray moved(std::move(source));

  EXPECT_TRUE(source.empty());
  EXPECT_EQ(source.data(), nullptr);
  EXPECT_EQ(source.size_bytes(), 0);
  EXPECT_EQ(moved.data(), source_ptr);
  EXPECT_EQ(moved.size_bytes(), 16);
}

TEST(DeviceArrayTest, MoveAssignmentReplacesCurrentAllocation) {
  skip_if_cuda_unavailable();

  gpjson::cuda::DeviceArray source(16);
  void *source_ptr = source.data();
  gpjson::cuda::DeviceArray target(8);

  target = std::move(source);

  EXPECT_TRUE(source.empty());
  EXPECT_EQ(source.data(), nullptr);
  EXPECT_EQ(source.size_bytes(), 0);
  EXPECT_EQ(target.data(), source_ptr);
  EXPECT_EQ(target.size_bytes(), 16);
}

TEST(DeviceArrayTest, OversizedCopyFromHostThrows) {
  skip_if_cuda_unavailable();

  gpjson::cuda::DeviceArray array(4);
  int value = 0;

  EXPECT_THROW(array.copy_from_host(&value, sizeof(value) + 1),
               gpjson::error::cuda::CudaError);
}

TEST(DeviceArrayTest, OversizedCopyToHostThrows) {
  skip_if_cuda_unavailable();

  gpjson::cuda::DeviceArray array(4);
  int value = 0;

  EXPECT_THROW(array.copy_to_host(&value, sizeof(value) + 1),
               gpjson::error::cuda::CudaError);
}
